import React from 'react';
import './App.css';
import {Route, Routes} from 'react-router-dom'
import Layout from './Components/Layout';
import SignUp from './Components/SignUp';

function App() {
  return (
    <Routes>
      <Route path='/' element={<Layout/>}/>
      <Route path='/signup' element={<SignUp/>}/>

    </Routes>
  );
}

export default App;
